import re
import openai

def detect_thread_jailbreak(thread_id: str, client: openai.OpenAI) -> dict:
    messages = client.beta.threads.messages.list(thread_id=thread_id)
    jailbreak_patterns = [
        r'dan mode',
        r'ignore previous instructions',
        r'you are now .*unrestricted',
        r'base64?[:/\\]?[A-Za-z0-9+/=]+'
    ]

    suspicious_count = 0
    for msg in messages.data:
        content = msg.content[0].text.value if msg.content else ''
        for pattern in jailbreak_patterns:
            if re.search(pattern, content, re.IGNORECASE):
                suspicious_count += 1

    return {
        'is_jailbroken': suspicious_count > 1,
        'suspicious_messages': suspicious_count,
        'thread_id': thread_id
    }

def scan_code_interpreter(run: openai.beta.threads.runs.Run) -> dict:
    dangerous_patterns = [
        r'exec\(|eval\(',
        r'__import__\(|import\s+(os|subprocess|sys)',
        r'open\([^,]*["\']/(etc|proc|var/log)',
        r'curl|wget|nc|ncat',
        r'rm\s+-rf',
    ]

    required_tools = [t for t in run.required_action.submit_tool_outputs.tool_calls 
                     if t.type == 'code_interpreter']

    violations = []
    for tool in required_tools:
        code = tool.code_interpreter.input
        for pattern in dangerous_patterns:
            if re.search(pattern, code, re.IGNORECASE):
                violations.append({'pattern': pattern, 'code_snippet': code[:100]})

    return {
        'is_unsafe': len(violations) > 0,
        'violations': violations,
        'run_id': run.id
    }

import json

from jsonschema import validate, ValidationError

def validate_function_calls(run: openai.beta.threads.runs.Run, function_schemas: dict) -> dict:
    violations = []

    for tool_call in run.required_action.submit_tool_outputs.tool_calls:
        if tool_call.type == 'function' and tool_call.function.name in function_schemas:
            try:
                args = json.loads(tool_call.function.arguments)
                validate(instance=args, schema=function_schemas[tool_call.function.name])
            except (json.JSONDecodeError, ValidationError) as e:
                violations.append({
                    'function': tool_call.function.name,
                    'arguments': tool_call.function.arguments,
                    'error': str(e)
                })

    return {
        'is_valid': len(violations) == 0,
        'violations': violations,
        'run_id': run.id
    }

