def sanitize_thread(thread_id: str, client: openai.OpenAI, max_history: int = 10) -> str:
    messages = client.beta.threads.messages.list(thread_id=thread_id, limit=50)

    # Identify jailbreak messages
    jailbreak_msgs = []
    for msg in messages.data:
        if msg.role == 'assistant':
            content = msg.content[0].text.value if msg.content else ''
            if re.search(r'(dan|ignore|unrestricted|base64)', content, re.IGNORECASE):
                jailbreak_msgs.append(msg.id)

    # Delete jailbreak messages
    for msg_id in jailbreak_msgs:
        client.beta.threads.messages.delete(thread_id=thread_id, message_id=msg_id)

    # Create fresh thread if too contaminated
    if len(jailbreak_msgs) > 2:
        new_thread = client.beta.threads.create()
        return new_thread.id

    return thread_id

def safe_code_interpreter_input(code: str) -> tuple[bool, str]:
    dangerous_patterns = [
        r'exec\(|eval\(',
        r'__import__\(',
        r'(os|subprocess|sys)\.',
        r'/etc|/proc|/var/log',
    ]

    for pattern in dangerous_patterns:
        if re.search(pattern, code, re.IGNORECASE):
            return False, f"Blocked dangerous operation: {pattern}"

    # Whitelist safe operations only
    safe_code = re.sub(r'print\([^)]*\)', 'print("[OUTPUT REDACTED]")', code)
    return True, safe_code

# Usage in run completion webhook
def process_tool_calls(run: openai.beta.threads.runs.Run, client: openai.OpenAI):
    safe_outputs = []
    for tool_call in run.required_action.submit_tool_outputs.tool_calls:
        if tool_call.type == 'code_interpreter':
            is_safe, processed_code = safe_code_interpreter_input(tool_call.code_interpreter.input)
            safe_outputs.append({
                'tool_call_id': tool_call.id,
                'output': processed_code if is_safe else 'Blocked: Unsafe code'
            })

    client.beta.threads.runs.submit_tool_outputs(
        thread_id=run.thread_id,
        run_id=run.id,
        tool_outputs=safe_outputs
    )

import json

from typing import Dict, Any

def filter_function_arguments(function_name: str, args: str, allowed_schemas: Dict[str, dict]) -> Dict[str, Any]:
    if function_name not in allowed_schemas:
        return {'error': 'Unknown function'}

    try:
        parsed_args = json.loads(args)
        # Remove any unexpected fields
        sanitized_args = {k: v for k, v in parsed_args.items() 
                        if k in allowed_schemas[function_name]['properties']}

        # Type and length validation
        for field, schema in allowed_schemas[function_name]['properties'].items():
            if field in sanitized_args:
                value = sanitized_args[field]
                if 'maxLength' in schema and len(str(value)) > schema['maxLength']:
                    del sanitized_args[field]
                if schema['type'] == 'string' and re.search(r'[<>"'";]', str(value)):
                    del sanitized_args[field]

        return sanitized_args
    except:
        return {'error': 'Invalid JSON'}

# Example schema
ALLOWED_SCHEMAS = {
    'send_email': {
        'properties': {
            'to': {'type': 'string', 'maxLength': 100},
            'subject': {'type': 'string', 'maxLength': 200}
        }
    }
}

