import openai
from vex_sdk import VexClient, Verification
from vex_sdk.types import WebhookEvent

# Initialize Vex client
vex = VexClient(api_key="your-vex-api-key")

@vex.webhook_handler("openai_assistant_run")
def verify_assistant_run(event: WebhookEvent, client: openai.OpenAI):
    run_data = event.data
    thread_id = run_data['thread_id']
    run_id = run_data['id']

    # Fetch run details
    run = client.beta.threads.runs.retrieve(
        thread_id=thread_id,
        run_id=run_id
    )

    # Multi-stage verification
    verifications = [
        Verification(
            name="jailbreak_detection",
            fn=detect_thread_jailbreak,
            args={'thread_id': thread_id, 'client': client}
        ),
        Verification(
            name="code_safety",
            fn=scan_code_interpreter,
            args={'run': run}
        ),
        Verification(
            name="function_schema",
            fn=validate_function_calls,
            args={'run': run, 'function_schemas': YOUR_SCHEMAS}
        )
    ]

    # Execute verification pipeline
    results = vex.verify(verifications)

    # Auto-remediate
    if not all(r.passed for r in results):
        clean_thread = sanitize_thread(thread_id, client)
        vex.log_remediation(f"Jailbreak detected and remediated. New thread: {clean_thread}")

        # Block run completion
        client.beta.threads.runs.cancel(thread_id=thread_id, run_id=run_id)

    return {'status': 'verified', 'issues': [r for r in results if not r.passed]}

# Register webhook with OpenAI
openai.beta.assistants.update(
    assistant_id="your-assistant-id",
    tool_resources={
        "webhook": {
            "url": vex.webhook_url,
            "events": ["thread.run.completed", "thread.run.requires_action"]
        }
    }
)
